('agspr', 'Fields', 'searchfor', 'Search For*', 'c', '50', '0', 'select', NULL, NULL, NULL, NULL, 'select cast(sf as varchar(50)),fname,fromdt,todt,ordno,dcname,slno from(
select cast(period as varchar(50))as sf,period as fname,fromdt,todt,1 as ordno,null as dcname, 1 as slno from (
select ''As on today'' as period,''current_date''  as fromdt,''current_date'' as todt from dual
           union all
           select ''As of yesterday'' as period,''current_date-1'' as fromdt,''current_date-1'' as dt from dual
           union all
           select ''As of this month'' as period,''date_trunc(''''month'''',current_date)'' as fromdt ,''current_date'' as todt from dual
            union all
           select ''As of this week'' as period,''date_trunc(''''week'''',current_date)'' as fromdt ,''current_date'' as todt from dual
            union all
           select ''As of last month'' as period,''date_trunc(''''month'''',(add_months(current_date,0-1)))'' as fromdt ,''date_trunc(''''month'''', current_date) + interval ''''0 month'''' - interval ''''1 day'''''' as todt from dual
            union all
           select ''As of last week'' as period,''date_trunc(''''week'''',current_date-7)'' as fromdt ,''date_trunc(''''week'''',current_date-7)+ interval ''''6 day'''''' as todt from dual
) a where :hltype =''iview'' and :periodically = ''T''
union all
