AND  ( COALESCE(allowduplicate,''T'')=''T'' and lower(modeofentry)<>''autogenerate'') and   :periodically =''F''
union all
  select  pcaption||''(''|| pname ||'')'' as sf, pname,null as fromdt,null as todt,1 as ordno,null dcname,5 as slno from iviewparams where iname= :structname  
and :hltype = ''iview'' and :periodically = ''F''
and moe in (''Select'',''Accept'',''Pick List''))x
order by slno,ordno
