('ad_af', 'Fields', 'fType', 'Field type*', 'c', '100', '0', 'select', NULL, NULL, NULL, NULL, 'select cast(typename as varchar(100)) typename,cnd,datatype fldtype,width fldwidth,deci,modeofentry,customdatatype  from 
(
select typename,case when typename in (''Short Text'',''Rich Text'',''Simple Text'',''Whole Number'',''Date'',''Time'',''Boolean'',
''File upload field'',''Image'',''Email'',''Mobile Number'',''Address'',''Zip Code'',''Pin Code'',''URL'',''Website'', ''Large Text'',
''Check box'', ''IP Address'',''Phone Number'',''Password'', ''Currency'', ''Whole Number'', ''Random Number'') then 1
when typename = ''Decimal Number'' then 2
when typename in(''Date Range'', '''', ''Number range'', ''Time Range'') then 3
when typename in(''CheckList'',''RadioGroup'') then 5
when typename = ''Auto Generate'' then 6 
when typename =''Table'' then 7
end cnd,datatype,width,deci,
case when typename in(''RadioGroup'') then ''Select From List'' else modeofentry end modeofentry,typename customdatatype 
from customtypes
where typename not in(''HTML Text'',''Expression Editor'',''SQL Editor'',''Multi Select'',''DropDown'',''CheckList'',''Boolean'',''Address'',''Date Range'',''File upload field'',''Number range'',''Time Range'',''Website'')
and  :asgrid =''F''
union all
select typename,case when typename in (''Short Text'',''Rich Text'',''Simple Text'',''Whole Number'',''Date'',''Time'',''Boolean'',
''File upload field'',''Image'',''Email'',''Mobile Number'',''Address'',''Zip Code'',''Pin Code'',''URL'',''Website'', ''Large Text'',
''Check box'', ''IP Address'',''Phone Number'',''Password'', ''Currency'', ''Whole Number'', ''Random Number'') then 1
when typename = ''Decimal Number'' then 2
when typename in(''Date Range'', '''', ''Number range'', ''Time Range'') then 3
when typename in(''CheckList'',''RadioGroup'') then 5
when typename = ''Auto Generate'' then 6 
when typename =''Table'' then 7
end cnd,datatype,width,deci,
case when typename in(''RadioGroup'') then ''Select From List'' else modeofentry end modeofentry,typename customdatatype 
from customtypes
where typename not in(''HTML Text'',''Expression Editor'',''SQL Editor'',''Multi Select'',''DropDown'',''CheckList'',''Boolean'',''Address'',''Date Range'',''File upload field'',''Number range'',''Time Range'',''Website'',''Image'',''Rich Text'',''Check box'',''CheckList'',''RadioGroup'',''Auto Generate'')
and  :asgrid =''T''
union all
select ''Dropdown from form'',4 cnd,''Character'',100,0,''Select From Form'',''DropDown''  from dual 
union all
select ''Dropdown from static list'',5 cnd,''Character'',100,0,''Select From List'',''DropDown''  from dual 
union all
select ''Dropdown from API'',10 cnd,''Character'',100,0,''Select From API'',''DropDown''  from dual 
union all
select ''DropDown'',8 cnd,''Character'',8000,0,''Select From Sql'',''DropDown'' from dual where 1=2
union all
select ''CheckList from form'',4 cnd,''Character'',100,0,''Select From Form'',''CheckList''  from dual where ''F'' = :asgrid
union all
select ''CheckList from static list'',5 cnd,''Character'',100,0,''Select From List'',''CheckList''  from dual  where ''F'' = :asgrid
)a
order by 1
